import subprocess
import json
import sys
import re

TARGET = '{target}'

def whois_lookup(domain):
    try:
        result = subprocess.run(['whois', domain], capture_output=True, text=True, timeout=15)
        return result.stdout[:2000]
    except: return ''

def dns_enum(domain):
    records = {}
    for rtype in ['A', 'AAAA', 'MX', 'NS', 'TXT', 'CNAME', 'SOA']:
        try:
            result = subprocess.run(['dig', '+short', rtype, domain], capture_output=True, text=True, timeout=5)
            if result.stdout.strip():
                records[rtype] = result.stdout.strip().split('\n')
        except: pass
    return records

def subdomain_enum(domain):
    subs = []
    common = ['www', 'mail', 'ftp', 'admin', 'vpn', 'remote', 'api', 'dev', 'staging', 'test', 'portal', 'webmail', 'owa', 'autodiscover', 'mx', 'ns1', 'ns2']
    for sub in common:
        try:
            result = subprocess.run(['dig', '+short', f'{sub}.{domain}'], capture_output=True, text=True, timeout=3)
            if result.stdout.strip():
                subs.append(f'{sub}.{domain}: {result.stdout.strip()}')
        except: pass
    return subs

print(f'=== OSINT Recon ===')
print(f'Target: {TARGET}')

print(f'\n--- DNS Records ---')
dns = dns_enum(TARGET)
for rtype, records in dns.items():
    print(f'  {rtype}: {records}')

print(f'\n--- Subdomains ---')
subs = subdomain_enum(TARGET)
for s in subs:
    print(f'  {s}')

print(f'\n--- WHOIS ---')
whois = whois_lookup(TARGET)
for line in whois.split('\n')[:15]:
    if line.strip():
        print(f'  {line.strip()}')
